import SwiftUI

struct gpumonitorview: View { @StateObject private var manager = GPUUtilizationMonitorManager(); var body: some View { ScrollView { VStack(alignment: .leading, spacing: 18) { JuicerFeatureHeader(title: "GPU Utilization Monitor", subtitle: "GPU load and display hardware information.", icon: "display.2", refreshing: manager.refreshing, action: manager.refresh); JuicerMetricTile(title: "Utilization", value: SystemMetricsSupport.percent(manager.reading.usage), detail: manager.reading.name, color: .blue); JuicerFeatureList(title: "GPU details") { Text(manager.reading.name); Text(manager.reading.memory).foregroundStyle(.secondary) } }.padding(24) }.onAppear { manager.refresh() } } }
struct diskiomonitorview: View { @StateObject private var manager = DiskIOMonitorManager(); var body: some View { ScrollView { VStack(alignment: .leading, spacing: 18) { JuicerFeatureHeader(title: "Disk I/O Monitor", subtitle: "Live read and write throughput by storage device.", icon: "internaldrive", refreshing: manager.refreshing, action: manager.refresh); JuicerFeatureList(title: "Devices") { ForEach(manager.readings) { row in HStack { Text(row.name); Spacer(); Text("↓ \(SystemMetricsSupport.bytes(UInt64(max(0, row.readRate))))/s"); Text("↑ \(SystemMetricsSupport.bytes(UInt64(max(0, row.writeRate))))/s") }.monospacedDigit() }; if manager.readings.isEmpty { Text("Waiting for disk statistics…").foregroundStyle(.secondary) } } }.padding(24) }.onAppear { manager.refresh() } } }
struct networktrafficmonitorview: View { @StateObject private var manager = NetworkTrafficMonitorManager(); var body: some View { ScrollView { VStack(alignment: .leading, spacing: 18) { JuicerFeatureHeader(title: "Network Traffic Monitor", subtitle: "Interface throughput and active connection count.", icon: "network", refreshing: manager.refreshing, action: manager.refresh); JuicerMetricTile(title: "Connections", value: "\(manager.connections)", detail: "open network sockets", color: .green); JuicerFeatureList(title: "Interfaces") { ForEach(manager.readings) { row in HStack { Text(row.interface); Spacer(); Text("↓ \(SystemMetricsSupport.bytes(UInt64(max(0, row.download))))/s"); Text("↑ \(SystemMetricsSupport.bytes(UInt64(max(0, row.upload))))/s") }.monospacedDigit() } } }.padding(24) }.onAppear { manager.refresh() } } }
struct batteryhealthview: View { @StateObject private var manager = BatteryHealthManager(); var body: some View { ScrollView { VStack(alignment: .leading, spacing: 18) { JuicerFeatureHeader(title: "Battery Health Dashboard", subtitle: "Battery cycles, capacity, temperature, and charging state.", icon: "battery.100", refreshing: manager.refreshing, action: manager.refresh); HStack { JuicerMetricTile(title: "Health", value: SystemMetricsSupport.percent(manager.reading.capacity), detail: "design capacity", color: .green); JuicerMetricTile(title: "Cycles", value: "\(manager.reading.cycleCount)", detail: manager.reading.charging ? "charging" : "not charging", color: .orange); JuicerMetricTile(title: "Temperature", value: String(format: "%.1f°C", manager.reading.temperature), detail: manager.reading.present ? "battery detected" : "no battery", color: .red) } }.padding(24) }.onAppear { manager.refresh() } } }
struct startupitemview: View { @StateObject private var manager = StartupItemManager(); var body: some View { VStack(alignment: .leading) { JuicerFeatureHeader(title: "Startup Item Manager", subtitle: "Review launch agents, daemons, and login startup files.", icon: "arrow.up.forward.app", refreshing: manager.refreshing, action: manager.refresh); List(manager.items) { item in HStack { VStack(alignment: .leading) { Text(item.name); Text(item.path).font(.caption).foregroundStyle(.secondary) }; Spacer(); Toggle("Enabled", isOn: Binding(get: { item.enabled }, set: { _ in manager.toggle(item) })).labelsHidden() } }.listStyle(.inset) }.padding(24).onAppear { manager.refresh() } } }
struct loginitemdelayview: View { @StateObject private var manager = LoginItemDelayManager(); var body: some View { VStack(alignment: .leading) { JuicerFeatureHeader(title: "Login Item Delay Configurator", subtitle: "Keep startup responsive by assigning launch delays.", icon: "timer", refreshing: false, action: {}); HStack { Spacer(); Button("Add Delay") { manager.add() } }; List(manager.delays) { item in HStack { TextField("Name", text: Binding(get: { item.name }, set: { _ in })); Slider(value: Binding(get: { item.seconds }, set: { _ in }), in: 0...60); Text("\(Int(item.seconds))s").monospacedDigit(); Button(role: .destructive) { manager.remove(item) } label: { Image(systemName: "trash") } } }.listStyle(.inset) }.padding(24) } }
struct processkillerview: View { @StateObject private var manager = ProcessKillerManager(); var body: some View { VStack(alignment: .leading) { JuicerFeatureHeader(title: "Process Killer", subtitle: "Find and stop unresponsive processes.", icon: "xmark.octagon", refreshing: false, action: manager.refresh); TextField("Search processes", text: $manager.query).textFieldStyle(.roundedBorder).onChange(of: manager.query) { _ in manager.refresh() }; List(manager.processes) { process in HStack { VStack(alignment: .leading) { Text(process.name); Text("PID \(process.pid) · CPU \(SystemMetricsSupport.percent(process.cpu)) · MEM \(SystemMetricsSupport.percent(process.memory))").font(.caption).foregroundStyle(.secondary) }; Spacer(); Button("Stop") { manager.kill(process) }; Button("Force Quit", role: .destructive) { manager.kill(process, force: true) } } }.listStyle(.inset) }.padding(24).onAppear { manager.refresh() } } }
struct systemlogview: View { @StateObject private var manager = SystemLogManager(); var body: some View { VStack(alignment: .leading) { JuicerFeatureHeader(title: "System Log Viewer", subtitle: "Search recent unified system and user logs.", icon: "doc.text.magnifyingglass", refreshing: false, action: manager.refresh); TextField("Filter logs", text: $manager.query).textFieldStyle(.roundedBorder).onChange(of: manager.query) { _ in manager.refresh() }; List(manager.entries) { Text($0.text).font(.system(.caption, design: .monospaced)) }.listStyle(.inset) }.padding(24).onAppear { manager.refresh() } } }
struct kextmanagerview: View { @StateObject private var manager = KextManager(); var body: some View { VStack(alignment: .leading) { JuicerFeatureHeader(title: "Kernel Extension Manager", subtitle: "Inspect loaded legacy kernel extensions on Intel Macs.", icon: "puzzlepiece.extension", refreshing: false, action: manager.refresh); if !manager.supported { Text("No loaded KEXT data was returned. Modern Apple silicon systems use system extensions and DriverKit.").foregroundStyle(.secondary).padding(.vertical) }; List(manager.extensions) { ext in HStack { Text(ext.name); Spacer(); Text(ext.version).foregroundStyle(.secondary) } }.listStyle(.inset) }.padding(24).onAppear { manager.refresh() } } }
